function test_round_timeframe() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    $test_date = $exchange->parse8601('2019-08-12 13:22:08');
    assert($exchange->round_timeframe('5m', $test_date, ROUND_DOWN) === $exchange->parse8601('2019-08-12 13:20:00'));
    assert($exchange->round_timeframe('10m', $test_date, ROUND_DOWN) === $exchange->parse8601('2019-08-12 13:20:00'));
    assert($exchange->round_timeframe('30m', $test_date, ROUND_DOWN) === $exchange->parse8601('2019-08-12 13:00:00'));
    assert($exchange->round_timeframe('1d', $test_date, ROUND_DOWN) === $exchange->parse8601('2019-08-12 00:00:00'));
    assert($exchange->round_timeframe('5m', $test_date, ROUND_UP) === $exchange->parse8601('2019-08-12 13:25:00'));
    assert($exchange->round_timeframe('10m', $test_date, ROUND_UP) === $exchange->parse8601('2019-08-12 13:30:00'));
    assert($exchange->round_timeframe('30m', $test_date, ROUND_UP) === $exchange->parse8601('2019-08-12 13:30:00'));
    assert($exchange->round_timeframe('1h', $test_date, ROUND_UP) === $exchange->parse8601('2019-08-12 14:00:00'));
    assert($exchange->round_timeframe('1d', $test_date, ROUND_UP) === $exchange->parse8601('2019-08-13 00:00:00'));
}


function test_parse_timeframe() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    assert($exchange->parse_timeframe('1m') === 60);
    assert($exchange->parse_timeframe('5m') === 300);
    assert($exchange->parse_timeframe('1h') === 3600);
    assert($exchange->parse_timeframe('1d') === 86400);
    assert($exchange->parse_timeframe('1w') === 604800);
    assert($exchange->parse_timeframe('1M') === 2592000); // todo: just approx
    assert($exchange->parse_timeframe('1y') === 31536000); // todo: just approx
}


function test_timeframes() {
    test_round_timeframe();
    test_parse_timeframe();
}
